import React, { useEffect, useState } from "react";
import { useCart } from "./CartContext";
import { useNavigate } from "react-router-dom";

function Help() {
  const [medicines, setMedicines] = useState([]);
  const { cartItems, addToCart, increaseQty, decreaseQty } = useCart();
  const navigate = useNavigate();

  useEffect(() => {
    fetch("http://localhost:8080/medicines")
      .then((res) => res.json())
      .then((data) => setMedicines(data))
      .catch((err) => console.error(err));
  }, []);

  const getQty = (id) => {
    const item = cartItems.find((i) => i.id === id);
    return item ? item.quantity : 0;
  };

  const totalItems = cartItems.reduce((sum, i) => sum + i.quantity, 0);

  return (
    <div className="help-container">

      {/* HEADER */}
      <div className="help-header">
        <h2>Medicines</h2>

        <div className="cart-icon" onClick={() => navigate("/cart")}>
          🛒 <span className="badge">{totalItems}</span>
        </div>
      </div>

      {/* VERTICAL LIST */}
      <div className="medicine-list">
        {medicines.map((med) => {
          const qty = getQty(med.id);

          return (
            <div key={med.id} className="medicine-card">

              <div className="med-info">
                <h4>{med.name}</h4>
                <p>{med.description}</p>
                <p className="price">₹{med.price}</p>
                <p className="stock">Stock: {med.stock}</p>
              </div>

              <div className="med-actions">
                {qty === 0 ? (
                  <button
                    className="primary-btn"
                    onClick={() =>
                      addToCart({
                        id: med.id,
                        name: med.name
                      })
                    }
                    disabled={med.stock === 0}
                  >
                    {med.stock === 0 ? "Out of Stock" : "Add"}
                  </button>
                ) : (
                  <div className="qty-controls">
                    <button onClick={() => decreaseQty(med.id)}>-</button>
                    <span>{qty}</span>
                    <button
                      onClick={() => increaseQty(med.id)}
                      disabled={qty >= 5 || qty >= med.stock}
                    >
                      +
                    </button>
                  </div>
                )}
              </div>

            </div>
          );
        })}
      </div>
    </div>
  );
}

export default Help;
